// 天然 shadow 安全:样式附到图表自有 wrapper(非 document.head);ResizeObserver 观察容器,chart.remove() 时清理。
import { createChart, CandlestickSeries } from 'https://cdn.jsdelivr.net/npm/lightweight-charts@5.2.0/+esm';
const el = document.createElement('div'); el.style.width = '100%'; el.style.height = '400px'; shadowRoot.appendChild(el);
const chart = createChart(el, { height: 400 });
const series = chart.addSeries(CandlestickSeries);
series.setData(data.candles);
chart.timeScale().fitContent();

